diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..ab4797767e5a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4508,27 +4508,45 @@ static Instruction *foldICmpOrXX(ICmpInst &I, const SimplifyQuery &Q,
 }

 static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
-                                  InstCombinerImpl &IC) {
-  Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1), *A;
-  // Normalize xor operand as operand 0.
-  CmpInst::Predicate Pred = I.getPredicate();
-  if (match(Op1, m_c_Xor(m_Specific(Op0), m_Value()))) {
-    std::swap(Op0, Op1);
-    Pred = ICmpInst::getSwappedPredicate(Pred);
-  }
-  if (!match(Op0, m_c_Xor(m_Specific(Op1), m_Value(A))))
-    return nullptr;
-
-  // icmp (X ^ Y_NonZero) u>= X --> icmp (X ^ Y_NonZero) u> X
-  // icmp (X ^ Y_NonZero) u<= X --> icmp (X ^ Y_NonZero) u< X
-  // icmp (X ^ Y_NonZero) s>= X --> icmp (X ^ Y_NonZero) s> X
-  // icmp (X ^ Y_NonZero) s<= X --> icmp (X ^ Y_NonZero) s< X
-  CmpInst::Predicate PredOut = CmpInst::getStrictPredicate(Pred);
-  if (PredOut != Pred &&
-      isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
-    return new ICmpInst(PredOut, Op0, Op1);
-
-  return nullptr;
+                                   InstCombinerImpl &IC) {
+   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1), *A;
+   // Normalize xor operand as operand 0.
+   CmpInst::Predicate Pred = I.getPredicate();
+   if (match(Op1, m_c_Xor(m_Specific(Op0), m_Value()))) {
+     std::swap(Op0, Op1);
+     Pred = ICmpInst::getSwappedPredicate(Pred);
+   }
+   if (!match(Op0, m_c_Xor(m_Specific(Op1), m_Value(A))))
+     return nullptr;
+
+   // icmp (X ^ Y_NonZero) u>= X --> icmp (X ^ Y_NonZero) u> X
+   // icmp (X ^ Y_NonZero) u<= X --> icmp (X ^ Y_NonZero) u< X
+   // icmp (X ^ Y_NonZero) s>= X --> icmp (X ^ Y_NonZero) s> X
+   // icmp (X ^ Y_NonZero) s<= X --> icmp (X ^ Y_NonZero) s< X
+   CmpInst::Predicate PredOut = CmpInst::getStrictPredicate(Pred);
+   if (PredOut != Pred &&
+       isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
+     return new ICmpInst(PredOut, Op0, Op1);
+
+   // icmp (X ^ Y), X where X = ~Z  -->  icmp (Z ^ Y) swapped(pred), Z
+   // For example: (~Z ^ Y) s< ~Z  -->  (Z ^ Y) s> Z
+   Value *X;
+   if (match(Op1, m_Xor(m_Value(X), m_AllOnes()))) {
+     // Op0 = (~X ^ A), Op1 = ~X
+     // Transform: icmp pred (~X ^ A), ~X  -->  icmp swapped(pred) (X ^ A), X
+     Value *NewXor = IC.Builder.CreateXor(X, A);
+     return new ICmpInst(ICmpInst::getSwappedPredicate(I.getPredicate()),
+                         NewXor, X);
+   }
+   if (match(Op0, m_Xor(m_Value(X), m_AllOnes()))) {
+     // Op0 = ~X, Op1 = (~X ^ A)
+     // Transform: icmp pred ~X, (~X ^ A)  -->  icmp swapped(pred) (X ^ A), X
+     Value *NewXor = IC.Builder.CreateXor(X, A);
+     return new ICmpInst(ICmpInst::getSwappedPredicate(I.getPredicate()),
+                         NewXor, X);
+   }
+
+   return nullptr;
 }

 /// Try to fold icmp (binop), X or icmp X, (binop).
@@ -4669,6 +4687,25 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
     return new ICmpInst(Pred, Y, Z);
   }

+  // icmp pred (xor (xor X, -1), Y), (xor Z, -1)
+  //   --> icmp swapped_pred (xor X, Y), Z
+  // icmp pred (xor Z, -1), (xor (xor X, -1), Y)
+  //   --> icmp pred (xor X, Y), Z
+  {
+    Value *X, *Y, *Z;
+    if (match(Op0, m_c_Xor(m_Xor(m_Value(X), m_AllOnes()), m_Value(Y))) &&
+        match(Op1, m_Xor(m_Value(Z), m_AllOnes()))) {
+      Value *NewXor = Builder.CreateXor(X, Y);
+      return new ICmpInst(CmpInst::getSwappedPredicate(Pred), NewXor, Z);
+    }
+    if (match(Op0, m_Xor(m_Value(Z), m_AllOnes())) &&
+        match(Op1, m_c_Xor(m_Xor(m_Value(X), m_AllOnes()), m_Value(Y)))) {
+      Value *NewXor = Builder.CreateXor(X, Y);
+      return new ICmpInst(Pred, NewXor, Z);
+    }
+  }
+
+
   // icmp slt (A + -1), Op1 -> icmp sle A, Op1
   if (A && NoOp0WrapProblem && Pred == CmpInst::ICMP_SLT &&
       match(B, m_AllOnes()))

log.source_program:
define i1 @test_sle_xor(i32 %x, i32 %y) {
  %xor1 = xor i32 %y, -1
  %xor2 = xor i32 %xor1, %x
  %r = icmp sle i32 %xor2, %xor1
  ret i1 %r
}

log.expect_optimized_program:
define i1 @test_sle_xor(i32 %x, i32 %y) {
  %1 = xor i32 %y, %x
  %r = icmp sge i32 %1, %y
  ret i1 %r
}

log.current_optimized_program:
